+    const TAXONOMY_CODES: [HostCallErrorCode; 5] = [
+        HostCallErrorCode::Timeout,
+        HostCallErrorCode::Denied,
+        HostCallErrorCode::Io,
+        HostCallErrorCode::InvalidRequest,
+        HostCallErrorCode::Internal,
